import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const modelDir = path.resolve(__dirname, "../src/generated/model");
const indexPath = path.join(modelDir, "index.ts");

const header = `/**
 * Generated by orval v8.6.2 🍺
 * Do not edit manually.
 * Aerisun API
 * OpenAPI spec version: 0.1.0
 */

`;

async function rebuildModelIndex() {
  const entries = await fs.readdir(modelDir, { withFileTypes: true });
  const exportLines = entries
    .filter((entry) => entry.isFile() && entry.name.endsWith(".ts") && entry.name !== "index.ts")
    .map((entry) => entry.name.slice(0, -3))
    .sort((left, right) => left.localeCompare(right))
    .map((name) => `export * from './${name}';`);

  await fs.writeFile(indexPath, `${header}${exportLines.join("\n")}\n`);
}

await rebuildModelIndex();
